import xml.etree.ElementTree as ET
from xml.parsers.expat import ExpatError
import io

def validate_xml_file(file_content):
    """
    Validates an XML document from uploaded file content
    
    Args:
        file_content: bytes or string containing XML content
        
    Returns:
        tuple: (is_valid, error_message)
    """
    try:
        # Parse the XML content
        if isinstance(file_content, bytes):
            tree = ET.parse(io.BytesIO(file_content))
        else:
            tree = ET.parse(io.StringIO(file_content))
        
        # If we get here, XML is well-formed
        return True, "XML is valid"
        
    except ET.ParseError as e:
        return False, f"XML Parse Error: {str(e)}"
    except ExpatError as e:
        return False, f"XML Expat Error: {str(e)}"
    except Exception as e:
        return False, f"Unexpected error: {str(e)}"

def validate_xml_string(xml_string):
    """
    Validates XML string directly
    
    Args:
        xml_string: string containing XML content
        
    Returns:
        tuple: (is_valid, error_message)
    """
    try:
        ET.fromstring(xml_string)
        return True, "XML is valid"
    except ET.ParseError as e:
        return False, f"XML Parse Error: {str(e)}"
    except Exception as e:
        return False, f"Unexpected error: {str(e)}"